CREATE VIEW `ads_consume_user_consume_explode_view` (`dt` COMMENT "createtime 分区", `product_id` COMMENT "产品id", `auto_id` COMMENT "自增id", `types` COMMENT "1：阅币，2：礼券,3：赠送币,4:vip", `user_id` COMMENT "用户ID", `amount` COMMENT "消费数额", `consume_cnt` COMMENT "消费次数", `remain_amount` COMMENT "剩余数额(阅币、礼券、赠送币、vip)", `book_id` COMMENT "书籍ID", `chapter_ids` COMMENT "章节id组，存在多个ID，以【逗号】分割", `chapter_id` COMMENT "章节id", `createtime` COMMENT "创建时间", `pay_type` COMMENT "付款方式 对应dim_paytype表中类型（注意：paytype<>1103)", `mt` COMMENT "平台 0未知 1iphone 4安卓 9书城", `seq` COMMENT "序号id", `app_id` COMMENT "项目id，core，语言", `position_id` COMMENT "埋点id", `app_game_id` COMMENT "游戏id", `send_id` COMMENT "发送id", `isFirst` COMMENT "是否首次购买", `etl_time` COMMENT "etl清洗时间")
